var distanceLimitedPathsExist = function(n, edgeList, queries) {
  const parent = new Array(n);
  for (let i = 0; i < n; i++) parent[i] = i;
  function find(x) {
    while (parent[x] !== x) {
      parent[x] = parent[parent[x]];
      x = parent[x];
    }
    return x;
  }
  function union(a, b) {
    const ra = find(a), rb = find(b);
    if (ra !== rb) parent[ra] = rb;
  }
  const edges = edgeList.slice().sort((a, b) => a[2] - b[2]);
  const m = queries.length;
  const order = Array.from({ length: m }, (_, i) => i);
  order.sort((a, b) => queries[a][2] - queries[b][2]);
  const ans = new Array(m).fill(false);
  let ei = 0;
  for (const qi of order) {
    const p = queries[qi][0], q = queries[qi][1], limit = queries[qi][2];
    while (ei < edges.length && edges[ei][2] < limit) {
      union(edges[ei][0], edges[ei][1]);
      ei++;
    }
    ans[qi] = find(p) === find(q);
  }
  return ans;
};
